-- Schema
CREATE TABLE products (
    id SERIAL PRIMARY KEY,
    name TEXT NOT NULL,
    category TEXT NOT NULL,
    price DECIMAL(10,2),
    attributes JSONB DEFAULT '{}'
);

-- GIN index cho containment và key existence
CREATE INDEX idx_products_attrs_gin ON products USING GIN (attributes);

-- Containment: tìm sản phẩm có color = 'red'
SELECT * FROM products WHERE attributes @> '{"color": "red"}';

-- Key existence
SELECT * FROM products WHERE attributes ? 'wifi_speed';

-- Path access
SELECT name, attributes->>'cpu' AS cpu
FROM products WHERE category = 'laptop';

-- JSONPath (PostgreSQL 12+) — phức tạp hơn
SELECT * FROM products
WHERE jsonb_path_exists(
    attributes, '$.sizes[*] ? (@ == "XL")');

-- Cập nhật field trong JSONB
UPDATE products
SET attributes = attributes || '{"stock": 50}'::jsonb
WHERE id = 1;

-- Remove key
UPDATE products
SET attributes = attributes - 'temp_flag'
WHERE category = 'electronics';

-- Index trên specific path (hữu ích khi query field cụ thể nhiều)
CREATE INDEX idx_products_color ON products ((attributes->>'color'))
WHERE attributes ? 'color';
